#include <stdio.h>
#include <stdint.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        int x;
        int64_t sum = 0;
        for (int i = 0; i < N; ++i) {
            scanf("%d", &x);
            sum += x;
        }
        int64_t expected = (int64_t)N * (N + 1) / 2;
        printf("%lld\n", expected - sum);
    }
    return 0;
}

